#include <stdio.h>
#include <openssl/bn.h>

void printBN(char *msg, BIGNUM *a) {
    char *number_str = BN_bn2hex(a);
    printf("%s%s\n", msg, number_str);
    OPENSSL_free(number_str);
}

int main() {
    BN_CTX *ctx = BN_CTX_new();
    BIGNUM *n = BN_new();
    BIGNUM *e = BN_new();
    BIGNUM *s = BN_new();
    BIGNUM *m_result = BN_new();

    BN_hex2bn(&n, ""); 

    BN_hex2bn(&e, "10001");

    BN_hex2bn(&s, "");

    BN_mod_exp(m_result, s, e, n, ctx);

    printBN("Decrypted Message : ", m_result);

    return 0;
}